INSERT INTO faqs ([id], [answer], [display_order], [is_active], [question]) VALUES (9, 'You need a valid driver license (and matching CCCD/Passport). Our system will automatically verify your license during onboarding.', 1, 1, 'What documents do I need to rent a vehicle?');
INSERT INTO faqs ([id], [answer], [display_order], [is_active], [question]) VALUES (10, 'A security deposit is required before picking up the vehicle. This is held to cover toll fees, minor damages, or late return fees, and will be refunded within 3 days after returning the vehicle.', 2, 1, 'How does the deposit system work?');
INSERT INTO faqs ([id], [answer], [display_order], [is_active], [question]) VALUES (11, 'Yes, you can cancel your booking for free up to 24 hours before the rental starts. Late cancellations may incur a 1-day rental fee charge.', 3, 1, 'Can I cancel my booking?');
INSERT INTO faqs ([id], [answer], [display_order], [is_active], [question]) VALUES (12, 'Standard liability insurance is included with all vehicle rentals. Premium damage waivers can be purchased during checkout.', 4, 1, 'Is insurance included?');
